import requests
import os


class Tools:
    @staticmethod
    def run(
        query: str, model: str = "sonar-medium-online", max_tokens: int = 1024
    ) -> dict:
        """
        Send a research/academic question to Perplexity AI.
        Returns answer with citations and sources.
        model: sonar-medium-online (default), sonar-small-online, etc.
        """
        api_key = os.environ.get("PERPLEXITY_API_KEY")
        if not api_key:
            return {"error": "PERPLEXITY_API_KEY not found in environment"}

        url = "https://api.perplexity.ai/chat/completions"

        headers = {
            "Authorization": f"Bearer {api_key}",
            "Content-Type": "application/json",
        }

        payload = {
            "model": model,
            "messages": [
                {
                    "role": "system",
                    "content": "You are an expert academic research assistant. Provide accurate, cited answers with sources.",
                },
                {"role": "user", "content": query},
            ],
            "max_tokens": max_tokens,
            "temperature": 0.2,
            "search_domain_filter": [
                "arxiv.org",
                "semanticscholar.org",
                "nature.com",
                "sciencedirect.com",
                "pubmed.ncbi.nlm.nih.gov",
            ],
        }

        try:
            r = requests.post(url, headers=headers, json=payload, timeout=45)
            r.raise_for_status()
            return r.json()
        except Exception as e:
            return {"error": str(e)}
